BEGIN;
CREATE TABLE market.cot_currency_mappings(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),currency_code text UNIQUE NOT NULL,currency_name text NOT NULL,market_name text NOT NULL,report_type text NOT NULL DEFAULT 'FUTURES_ONLY',enabled boolean NOT NULL DEFAULT true,config jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE market.cot_reports(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),report_date date NOT NULL,report_type text NOT NULL,source_year integer NOT NULL,source_file text NOT NULL,source_url text NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(report_date,report_type,source_file));
CREATE TABLE market.cot_import_batches(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),batch_key text UNIQUE NOT NULL,report_type text NOT NULL,source_year integer NOT NULL,status text NOT NULL,records_found integer NOT NULL DEFAULT 0,records_imported integer NOT NULL DEFAULT 0,records_updated integer NOT NULL DEFAULT 0,duplicates_skipped integer NOT NULL DEFAULT 0,failed_records integer NOT NULL DEFAULT 0,started_at timestamptz NOT NULL DEFAULT now(),completed_at timestamptz);
CREATE TABLE market.cot_positions(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),report_date date NOT NULL,currency_code text NOT NULL REFERENCES market.cot_currency_mappings(currency_code),currency_name text NOT NULL,market_name text NOT NULL,report_type text NOT NULL,long_positions bigint NOT NULL,short_positions bigint NOT NULL,change_long bigint NOT NULL,change_short bigint NOT NULL,percent_change numeric(12,4) NOT NULL,net_positions bigint NOT NULL,open_interest bigint NOT NULL,long_percent numeric(12,4),short_percent numeric(12,4),net_open_interest_percent numeric(12,4),commercial_long bigint,commercial_short bigint,non_commercial_long bigint,non_commercial_short bigint,non_commercial_spreading bigint,bias text NOT NULL,bias_confidence numeric(7,4) NOT NULL,source_year integer NOT NULL,source_file text NOT NULL,import_batch_id uuid REFERENCES market.cot_import_batches(id),created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(report_date,currency_code,report_type));
CREATE TABLE market.cot_position_changes(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),position_id uuid NOT NULL REFERENCES market.cot_positions(id),change_long bigint NOT NULL,change_short bigint NOT NULL,net_change bigint NOT NULL,change_4w bigint,percentile_13w numeric(7,4),percentile_52w numeric(7,4),created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE market.cot_bias_scores(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),position_id uuid NOT NULL REFERENCES market.cot_positions(id),currency_code text NOT NULL,bias text NOT NULL,confidence numeric(7,4) NOT NULL,reason text NOT NULL,workflow_permission text NOT NULL,warnings jsonb NOT NULL DEFAULT '[]'::jsonb,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE market.cot_sync_jobs(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),job_name text UNIQUE NOT NULL,cron_expression text NOT NULL,enabled boolean NOT NULL DEFAULT true,retry_limit integer NOT NULL DEFAULT 3,last_status text,next_run_at timestamptz,updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE market.cot_sync_logs(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),sync_id text UNIQUE NOT NULL,batch_id uuid REFERENCES market.cot_import_batches(id),status text NOT NULL,source_url text NOT NULL,report_type text NOT NULL,source_year integer,records_found integer NOT NULL DEFAULT 0,records_imported integer NOT NULL DEFAULT 0,records_updated integer NOT NULL DEFAULT 0,duplicates_skipped integer NOT NULL DEFAULT 0,errors integer NOT NULL DEFAULT 0,triggered_by text NOT NULL,duration_ms integer,log_payload jsonb NOT NULL DEFAULT '{}'::jsonb,started_at timestamptz NOT NULL DEFAULT now(),completed_at timestamptz);
CREATE TABLE market.cot_raw_files(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),batch_id uuid REFERENCES market.cot_import_batches(id),source_year integer NOT NULL,file_name text NOT NULL,content_type text NOT NULL,checksum text NOT NULL,storage_path text NOT NULL,downloaded_at timestamptz NOT NULL DEFAULT now(),UNIQUE(source_year,file_name,checksum));
CREATE TABLE market.cot_workflow_impacts(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),workflow_stage text UNIQUE NOT NULL,usage text NOT NULL,enabled boolean NOT NULL DEFAULT true,created_at timestamptz NOT NULL DEFAULT now());
INSERT INTO market.cot_sync_jobs(job_name,cron_expression,retry_limit,last_status) VALUES ('cot_weekly_sync_job','0 0 * * 6',3,'READY');
COMMIT;
